import games from '../games';
import '../index.css';
import { Link } from "react-router-dom";

const GamePage = () => (
  <div className="main">
    <h1>
      Games
    </h1>
    
    {games.map(({image, name, desc }, key) => (
      <Frame image={image} title={name} desc={desc} key={key} />
    ))}
  </div>
)

const Frame = ({image, title = "Lol", desc = "Lol"}) => (
  <Link to={"/games/" + title}>
    <div className="frame-container">
      <div className="frame-image">
        <img src={image} alt="Game" />
      </div>
      <div className="frame-desc">
        <h1>
          {title}
        </h1>
        <p>
          {desc}
        </p>
      </div>
    </div>
  </Link>
)

export default GamePage;
